     1→/**
     2→ * @file Prettier plugin for standardizing line breaks (multi-line formatting)
     3→ * Goal: stabilize diffs in code reviews and improve readability by reducing
     4→ * inconsistencies from Prettier's default printWidth behavior.
     5→ *
     6→ * Main rules:
     7→ * 1. Enforces braces (`{}`) in `IfStatement` with long conditions.
     8→ * 2. Applies multi-line to `ArrayExpression` if `elements.length > arrayWrapThreshold`.
     9→ * 3. Applies multi-line to `ObjectExpression` if `properties.length > objectWrapThreshold`.
    10→ * 4. Applies multi-line to `TSTypeLiteral` if `members.length > objectWrapThreshold`.
    11→ * 5. Applies multi-line to function parameters (various `FUNCTION_NODE_TYPES`) if
    12→ *    param count (> 3) or param string length (> paramsPrintWidth) exceeds limits.
    13→ *
    14→ * @prettier
    15→ */
    16→import { doc } from 'prettier';
    17→import { printers as estreePrinters } from 'prettier/plugins/estree';
    18→
    19→const originalEstreePrinter = estreePrinters.estree;
    20→const { group, indent, line, softline, join, ifBreak } = doc.builders;
    21→
    22→const DEFAULT_THRESHOLD = 1;
    23→const DEFAULT_CONDITION_PRINT_WIDTH = 50;
    24→
    25→// A set of function-like node types that have a `params` property.
    26→const FUNCTION_NODE_TYPES = new Set([
    27→  'FunctionDeclaration',
    28→  'FunctionExpression',
    29→  'ArrowFunctionExpression',
    30→  'ObjectMethod',
    31→  'ClassMethod',
    32→  'TSDeclareMethod',
    33→  'TSFunctionType',
    34→  'TSMethodSignature',
    35→]);
    36→
    37→/**
    38→ * Creates a wrapped printer that applies custom formatting rules.
    39→ * @param {object} originalPrinter - The original Prettier printer to wrap.
    40→ * @returns {object} The new printer with the overridden print function.
    41→ */
    42→function createWrappedPrinter(originalPrinter) {
    43→  return {
    44→    ...originalPrinter,
    45→    print(
    46→      path,
    47→      options,
    48→      print
    49→    ) {
    50→      const node = path.getValue();
    51→
    52→      function getText() {
    53→        return (getText.cache = getText.cache ?? options.originalText.slice(...node.range));
    54→      }
    55→
    56→      // function getParamWidth() {
    57→      //   return (getParamWidth.cache =
    58→      //     getParamWidth.cache ?? getText().match(/^[^)]+\)/)?.[0].length);
    59→      // }
    60→
    61→      // Determine thresholds from options.
    62→      const multilineWrapThreshold = asInt(options.multilineWrapThreshold, DEFAULT_THRESHOLD);
    63→      const objectWrapThreshold = asInt(options.objectWrapThreshold, multilineWrapThreshold);
    64→      const arrayWrapThreshold = asInt(options.arrayWrapThreshold, objectWrapThreshold);
    65→      // prettier-ignore
    66→      const paramsPrintWidth = asInt(options.paramsPrintWidth, DEFAULT_CONDITION_PRINT_WIDTH);
    67→
    68→      const trailingComma =
    69→        options.trailingComma === 'all' || options.trailingComma === 'es5' ? ifBreak(',', '') : '';
    70→
    71→      // Handle IfStatement to enforce braces
    72→      if (
    73→        node?.type === 'IfStatement' &&
    74→        node.consequent &&
    75→        node.consequent.type !== 'BlockStatement' &&
    76→        getText().split(')')[0].length > paramsPrintWidth
    77→      ) {
    78→        const parts = [
    79→          'if (',
    80→          softline,
    81→          path.call(print, 'test'),
    82→          softline,
    83→          ') ',
    84→          '{',
    85→          indent([
    86→            line,
    87→            path.call(print, 'consequent'),
    88→          ]),
    89→          line,
    90→          '}',
    91→        ];
    92→
    93→        if (node.alternate) {
    94→          parts.push(' else ', path.call(print, 'alternate'));
    95→        }
    96→
    97→        return parts;
    98→      }
    99→
   100→      // Handle ArrayExpression nodes.
   101→      if (node?.type === 'ArrayExpression' && node.elements.length > arrayWrapThreshold) {
   102→        return group(
   103→          [
   104→            '[',
   105→            indent([
   106→              line,
   107→              join(
   108→                [
   109→                  ',',
   110→                  line,
   111→                ],
   112→                path.map(print, 'elements'),
   113→              ),
   114→              trailingComma,
   115→            ]),
   116→            line,
   117→            ']',
   118→          ],
   119→          { shouldBreak: true },
   120→        );
   121→      }
   122→
   123→      // Handle ObjectExpression nodes.
   124→      if (node?.type === 'ObjectExpression' && node.properties.length > objectWrapThreshold) {
   125→        const objectDoc = group(
   126→          [
   127→            '{',
   128→            indent([
   129→              line,
   130→              join(
   131→                [
   132→                  ',',
   133→                  line,
   134→                ],
   135→                path.map(print, 'properties'),
   136→              ),
   137→              trailingComma,
   138→            ]),
   139→            line,
   140→            '}',
   141→          ],
   142→          { shouldBreak: true },
   143→        );
   144→
   145→        const parentNode = path.getParentNode();
   146→        if (parentNode?.type === 'ArrowFunctionExpression' && parentNode.body === node) {
   147→          return [
   148→            '(',
   149→            objectDoc,
   150→            ')',
   151→          ];
   152→        }
   153→
   154→        return objectDoc;
   155→      }
