   162→            '{',
   163→            indent([
   164→              line,
   165→              join(
   166→                [
   167→                  trailingSemi,
   168→                  line,
   169→                ],
   170→                path.map(print, 'members'),
   171→              ),
   172→              trailingSemi,
   173→            ]),
   174→            line,
   175→            '}',
   176→          ],
   177→          { shouldBreak: true },
   178→        );
   179→      }
