   212→            doc.push('function');
   213→          }
   214→
   215→          if (node.generator) {
   216→            doc.push('*');
   217→          }
   218→          if (node.id) {
   219→            doc.push(' ', path.call(print, 'id'));
   220→          }
   221→        } else if (node.key) {
   222→          doc.push(path.call(print, 'key'));
   223→        }
   224→
   225→        if (node.typeParameters) {
   226→          doc.push(path.call(print, 'typeParameters'));
   227→        }
   228→
   229→        // Custom logic to force-break parameters.
   230→
   231→        doc.push(
   232→          group(
   233→            [
   234→              '(',
   235→              shouldBreakParams
   236→                ? indent([
   237→                  line,
   238→                  join(
